eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   featuredProjects: () => (/* binding */ featuredProjects),\n/* harmony export */   projects: () => (/* binding */ projects)\n/* harmony export */ });\nconst projects = [\n    {\n        slug: \"ridgewood-apartment\",\n        title: \"Ridgewood Apartment\",\n        tagline: \"A harmonious blend of nature-inspired design and contemporary luxury.\",\n        location: \"Gurgaon\",\n        year: \"2024\",\n        img: \"/images/projects/DSC06981.jpg\",\n        category: \"Residential\",\n        area: \"4,200 sq ft\",\n        description: \"A harmonious blend of nature-inspired design and contemporary luxury. The Ridgewood Apartment reimagines urban living through biophilic elements, natural stone textures, and a palette of deep greens and warm neutrals.\",\n        challenge: \"The client desired a space that felt connected to nature while maintaining the sophistication of a modern urban home. The existing layout was compartmentalized and lacked natural light flow.\",\n        solution: \"We opened up the floor plan to create seamless transitions between living areas, introduced floor-to-ceiling windows framed in blackened steel, and layered natural materials — travertine, walnut, and hand-troweled plaster — to evoke organic warmth throughout.\",\n        gallery: [\n            \"/images/projects/DSC06981.jpg\",\n            \"/images/projects/DSC07091.jpg\",\n            \"/images/projects/VANITY 5 (4).JPG\",\n            \"/images/projects/House 38.jpg\"\n        ]\n    },\n    {\n        slug: \"toni-and-guy\",\n        title: \"Toni & Guy\",\n        tagline: \"A masterclass in restrained opulence atop Delhi's prestigious addresses.\",\n        location: \"Faridabad\",\n        year: \"2023\",\n        img: \"/images/projects/DSC07329.jpg\",\n        category: \"Commercial\",\n        area: \"6,800 sq ft\",\n        description: \"Perched atop one of Delhi's most prestigious addresses, this flagship salon is a masterclass in restrained opulence. Every surface, from the book-matched marble to the custom bronze hardware, was selected to create an environment of effortless grandeur.\",\n        challenge: \"The expansive open-plan space risked feeling cold and impersonal. The client wanted distinct zones for different services while maintaining a unified luxury aesthetic.\",\n        solution: \"We introduced sculptural partitions in fluted glass and blackened oak, creating intimate pockets within the grand volume. A curated palette of ivory, champagne, and deep charcoal ties every zone together.\",\n        gallery: [\n            \"/images/projects/DSC07329.jpg\",\n            \"/images/projects/DSC07337.jpg\",\n            \"/images/projects/tng-1 - Edited.jpg\",\n            \"/images/projects/TONY _ GUY AGRA (20).jpg\"\n        ]\n    },\n    {\n        slug: \"timeless-fitness-gym\",\n        title: \"Timeless Fitness Gym\",\n        tagline: \"A high-end wellness destination where performance meets premium design.\",\n        location: \"Delhi\",\n        year: \"2024\",\n        img: \"/images/projects/House 6.jpg\",\n        category: \"Commercial\",\n        area: \"5,500 sq ft\",\n        description: \"A high-end wellness destination where performance meets premium design. Timeless Fitness reimagines the gym experience through a minimalist industrial lens, prioritizing raw textures and cinematic lighting.\",\n        challenge: \"Balancing the rugged requirements of a fitness center with the premium aesthetic of a luxury brand. The space needed to be durable yet visually sophisticated.\",\n        solution: \"We specified teak, terrazzo, and hand-poured concrete — materials that age gracefully. Integrated lighting systems highlight the architectural volumes, creating an atmosphere of focus and strength.\",\n        gallery: [\n            \"/images/projects/House 6.jpg\",\n            \"/images/projects/Malani Marble (40).jpg\",\n            \"/images/projects/TGP03823-HDR-1.jpg\"\n        ]\n    },\n    {\n        slug: \"naraina-vihar\",\n        title: \"Naraina Vihar Residence\",\n        tagline: \"Conceived as a gallery for living, treating every surface as artistic expression.\",\n        location: \"New Delhi\",\n        year: \"2023\",\n        img: \"/images/projects/TGP03936-HDR-1.jpg\",\n        category: \"Residential\",\n        area: \"3,800 sq ft\",\n        description: \"Conceived as a gallery for living, this apartment treats every wall, niche, and surface as an opportunity for artistic expression. The architecture recedes to let a world-class contemporary art collection take center stage.\",\n        challenge: \"The client's growing art collection demanded museum-quality display conditions within a space that still felt like a warm, inviting home.\",\n        solution: \"We designed a gallery-track lighting system integrated into recessed ceiling channels, paired with movable wall panels. Furnishings in muted tones ensure the art always commands attention.\",\n        gallery: [\n            \"/images/projects/TGP03936-HDR-1.jpg\",\n            \"/images/projects/Copy of TGP04029-HDR-1.jpg\",\n            \"/images/projects/House 39.jpg\"\n        ]\n    },\n    {\n        slug: \"pioneer-araya\",\n        title: \"Pioneer Araya\",\n        tagline: \"A sophisticated living space anchored by emerald-green and brass accents.\",\n        location: \"Gurgaon\",\n        year: \"2024\",\n        img: \"/images/projects/TONY _ GUY AGRA (20).jpg\",\n        category: \"Residential\",\n        area: \"3,200 sq ft\",\n        description: \"A sophisticated living space anchored by emerald-green tufted seating and brass accents. Pioneer Araya balances warmth and glamour through layered textures and bespoke details.\",\n        challenge: \"The client wanted a living room that felt both inviting for family evenings and impressive enough for formal entertaining.\",\n        solution: \"We designed a dual-purpose layout with movable accent furniture. Rich green velvet, geometric mosaic surfaces, and a warm metallic palette unify the space.\",\n        gallery: [\n            \"/images/projects/TONY _ GUY AGRA (20).jpg\",\n            \"/images/projects/tng-1 - Edited.jpg\",\n            \"/images/projects/DSC07091.jpg\"\n        ]\n    },\n    {\n        slug: \"the-artisan-bar\",\n        title: \"The Artisan Bar\",\n        tagline: \"A compact yet expressive lounge nook with a boutique hotel feel.\",\n        location: \"Chandigarh\",\n        year: \"2024\",\n        img: \"/images/projects/DSC07091.jpg\",\n        category: \"Residential\",\n        area: \"1,800 sq ft\",\n        description: \"A compact yet expressive bar and lounge nook featuring statement artwork, wooden ceiling beams, and striped marble flooring. Every corner is curated to feel like a boutique hotel experience.\",\n        challenge: \"Transforming a narrow, underutilized corridor space into a functional and visually striking home bar.\",\n        solution: \"We introduced a marble-top bar counter with integrated shelving, paired with a bold portrait painting as a focal anchor. Geometric pendant lights soften the proportions.\",\n        gallery: [\n            \"/images/projects/DSC07091.jpg\",\n            \"/images/projects/DSC07329.jpg\",\n            \"/images/projects/VANITY 5 (4).JPG\"\n        ]\n    },\n    {\n        slug: \"shukrana-residence\",\n        title: \"The Shukrana Residence\",\n        tagline: \"Celebrating Indian craftsmanship through a contemporary luxury lens.\",\n        location: \"New Delhi\",\n        year: \"2023\",\n        img: \"/images/projects/DSC07337.jpg\",\n        category: \"Luxury Residential\",\n        area: \"2,400 sq ft\",\n        description: \"A formal dining room where cascading gold chandeliers meet sapphire-blue velvet chairs. The space celebrates Indian craftsmanship through a contemporary lens.\",\n        challenge: \"The double-height dining area needed visual warmth and intimacy despite its grand proportions and abundance of hard surfaces.\",\n        solution: \"A cascading gold chandelier draws the eye downward, anchoring the space. Rich blue upholstery and curated wall art create layers of visual interest.\",\n        gallery: [\n            \"/images/projects/DSC07337.jpg\",\n            \"/images/projects/House 6.jpg\",\n            \"/images/projects/DSC06981.jpg\"\n        ]\n    },\n    {\n        slug: \"malani-marble\",\n        title: \"Malani Marble\",\n        tagline: \"A monumental showcase of natural stone as architectural sculpture.\",\n        location: \"Kishangarh\",\n        year: \"2023\",\n        img: \"/images/projects/Malani Marble (40).jpg\",\n        category: \"Commercial\",\n        area: \"12,000 sq ft\",\n        description: \"A monumental showroom designed to showcase natural stone not just as material, but as architectural sculpture. The space uses scale and light to dramatize the beauty of marble.\",\n        challenge: \"Displaying thousands of heavy stone slabs in a way that feels curated and light, rather than industrial or overwhelming.\",\n        solution: \"We created a series of monolithic display walls and integrated dramatic overhead lighting that mimics natural daylight.\",\n        gallery: [\n            \"/images/projects/Malani Marble (40).jpg\",\n            \"/images/projects/DSC06981.jpg\",\n            \"/images/projects/TGP03823-HDR-1.jpg\"\n        ]\n    },\n    {\n        slug: \"urban-art-gallery\",\n        title: \"Urban Art Gallery\",\n        tagline: \"A minimalist canvas where architecture recedes to empower the art.\",\n        location: \"New Delhi\",\n        year: \"2024\",\n        img: \"/images/projects/Copy of TGP04029-HDR-1.jpg\",\n        category: \"Cultural\",\n        area: \"5,800 sq ft\",\n        description: \"A minimalist gallery space designed as a silent canvas. High ceilings, seamless white surfaces, and precision lighting create an environment where the architecture empowers the art.\",\n        challenge: \"Creating a space that is flexible enough for large-scale installations while maintaining an intimate feel for smaller works.\",\n        solution: \"We implemented a system of modular wall panels and a programmable DALI lighting grid, allowing for complete transformation.\",\n        gallery: [\n            \"/images/projects/Copy of TGP04029-HDR-1.jpg\",\n            \"/images/projects/TGP03936-HDR-1.jpg\",\n            \"/images/projects/House 38.jpg\"\n        ]\n    },\n    {\n        slug: \"tg-studio\",\n        title: \"T&G Studio\",\n        tagline: \"A high-performance creative hub blending industrial grit with luxury finish.\",\n        location: \"Mumbai\",\n        year: \"2023\",\n        img: \"/images/projects/tng-1 - Edited.jpg\",\n        category: \"Workspace\",\n        area: \"2,500 sq ft\",\n        description: \"A creative hub designed for high-performance artistic work. The studio blends industrial elements like exposed ceilings with luxury finishes like fluted oak.\",\n        challenge: \"Balancing the technical requirements of a high-end salon workspace with the comfort and privacy of a luxury lounge.\",\n        solution: \"We designed bespoke workstations with integrated storage and lighting, using semi-transparent partitions to maintain an open feel.\",\n        gallery: [\n            \"/images/projects/tng-1 - Edited.jpg\",\n            \"/images/projects/TONY _ GUY AGRA (20).jpg\",\n            \"/images/projects/DSC07329.jpg\"\n        ]\n    }\n];\nconst featuredProjects = projects.slice(0, 3);\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./data/projects.ts\n");

